import { z } from "zod";
//#region src/lib/validations.ts
/**
* Shared field rules. Phone accepts Indian formats (+91 / 0-prefixed / 10 digits).
* Email uses zod's built-in check.
*/
var phone = z.string().trim().min(8, "Enter a valid phone number").max(20, "Phone number too long").regex(/^[+]?[\d\s()-]{8,20}$/, "Enter a valid phone number");
var email = z.string().trim().min(3).max(120).email("Enter a valid email");
z.object({ company: z.string().max(0).optional() }).optional();
var ConsultationSchema = z.object({
	name: z.string().trim().min(2, "Please enter your name").max(80),
	phone,
	email,
	experience: z.string().trim().min(1, "Required").max(40),
	current: z.string().trim().min(1, "Required").max(80),
	target: z.string().trim().min(1, "Required").max(80),
	preferredTime: z.string().trim().max(80).optional().default(""),
	message: z.string().trim().max(2e3).optional().default(""),
	company: z.string().max(0).optional(),
	turnstileToken: z.string().min(1).optional()
}).strip();
var WorkshopSchema = z.object({
	name: z.string().trim().min(2, "Please enter your name").max(80),
	phone,
	email,
	workshop: z.string().trim().min(2, "Select a workshop").max(120),
	company: z.string().max(0).optional(),
	turnstileToken: z.string().min(1).optional()
}).strip();
var ContactSchema = z.object({
	name: z.string().trim().min(2, "Please enter your name").max(80),
	phone,
	email,
	subject: z.string().trim().max(120).optional().default(""),
	message: z.string().trim().min(5, "Please add a message").max(2e3),
	company: z.string().max(0).optional(),
	turnstileToken: z.string().min(1).optional()
}).strip();
/** Honeypot guard shared by all forms. */
function isSpam(input) {
	if (input && typeof input === "object" && "company" in input) {
		const v = input.company;
		return typeof v === "string" && v.length > 0;
	}
	return false;
}
//#endregion
export { isSpam as i, ContactSchema as n, WorkshopSchema as r, ConsultationSchema as t };
